export const WORDS_JOHN1V1 = [
  { greek:"Ἐν", transliteration:"En", meaning:"In", grammar:"Preposition governing the dative case. One of the most common Greek prepositions, appearing ~2,752 times in the NT.", letters:[{l:"Ε",name:"Epsilon",lesson:5,note:"Short 'e' — the everyday vowel"},{l:"ν",name:"Nu",lesson:13,note:"The 'n' sound — completing the preposition"}], devotional:"The Gospel of John opens not with a birth narrative but with a preposition: 'in'. In the beginning. In the Word. In God. John's entire Gospel is an invitation to enter — to be in Christ, as Christ is in the Father.", color:"#1B7A6E" },
  { greek:"ἀρχῇ", transliteration:"archē", meaning:"Beginning", grammar:"Dative singular feminine of ἀρχή (archē). Root of 'archaeology' and 'archangel'. Signifies the absolute beginning — not a beginning in a series but the origin of all.", letters:[{l:"α",name:"Alpha",lesson:1,note:"The first letter — fitting for 'beginning'"},{l:"ρ",name:"Rho",lesson:17,note:"Vibrant 'r' — the sound of origin"},{l:"χ",name:"Chi",lesson:22,note:"'kh' sound — from which 'Christ' (Χριστός) derives"},{l:"η",name:"Eta",lesson:7,note:"Long 'e' — the enduring vowel"}], devotional:"Ἐν ἀρχῇ echoes the opening of Genesis: בְּרֵאשִׁית — 'in the beginning'. John deliberately mirrors Genesis. The Word who was in the beginning of the Gospel is the same Word through whom the beginning of creation came.", color:"#1A2F4B" },
  { greek:"ἦν", transliteration:"ēn", meaning:"Was (already existing)", grammar:"Imperfect active indicative 3rd singular of εἰμί (to be). The imperfect tense indicates continuous past existence — not 'came to be' (ἐγένετο) but 'was already there'. A key distinction proving the eternal pre-existence of the Word.", letters:[{l:"η",name:"Eta",lesson:7,note:"Long 'e' — the extended existence"},{l:"ν",name:"Nu",lesson:13,note:"Closing the word — was, enduring"}], devotional:"Three times in John 1:1, ἦν appears: 'In the beginning was the Word... the Word was with God... the Word was God.' Not three different verbs but the same continuous existence — eternal, relational, divine. The Word did not begin; the Word was.", color:"#2A5E58" },
  { greek:"ὁ", transliteration:"ho", meaning:"The", grammar:"Definite article, nominative masculine singular. Greek uses the article not just for definiteness but for identification. Here ὁ λόγος — 'the Word' — is a specific, identified person.", letters:[{l:"ο",name:"Omicron",lesson:15,note:"Short 'o' — the little vowel carrying great weight"}], devotional:"The definite article ὁ is one of the most powerful words in theology. John 1:1c reads 'θεὸς ἦν ὁ λόγος' — literally 'God was the Word'. Greek word order and the article tell us: the Word is God in nature, while God the Father is distinct in person. Centuries of Trinitarian theology hang on this tiny word.", color:"#1B7A6E" },
  { greek:"λόγος", transliteration:"logos", meaning:"Word / Reason / Logic", grammar:"Nominative masculine singular. Appears 330 times in the NT. In Greek philosophy, λόγος was the rational principle underlying the universe. John takes this concept and identifies it with a Person.", letters:[{l:"λ",name:"Lambda",lesson:11,note:"The 'l' of logic and law"},{l:"ο",name:"Omicron",lesson:15,note:"Short 'o'"},{l:"γ",name:"Gamma",lesson:3,note:"'g' sound — God's self-expression"},{l:"ο",name:"Omicron",lesson:15,note:"Short 'o'"},{l:"ς",name:"Sigma (final)",lesson:18,note:"Final sigma — ending with a whisper"}], devotional:"When John chose λόγος, every Greek philosopher would nod: yes, the rational principle behind existence. But then John said: ὁ λόγος became flesh. This was not philosophy — this was a person. The Logos was not an idea but a man you could touch. The Word that held the universe together wore sandals and wept at a tomb.", color:"#2A5E58" },
];

export const WORDS_JOHN3V16 = [
  { greek:"Οὕτως", transliteration:"Houtōs", meaning:"So / In this way", grammar:"Adverb indicating manner. Not 'so much' (a common misreading) but 'in this manner' — describing the nature of God's love as demonstrated by the gift of His Son.", letters:[{l:"Ο",name:"Omicron",lesson:15,note:"Short 'o' — beginning of the manner"},{l:"υ",name:"Upsilon",lesson:20,note:"The 'u' sound"},{l:"τ",name:"Tau",lesson:19,note:"The cross — τ is shaped like a cross"},{l:"ω",name:"Omega",lesson:24,note:"The great long 'o'"},{l:"ς",name:"Sigma (final)",lesson:18,note:"Sealing the word"}], devotional:"Οὕτως does not say God loved us 'so much' — it says God loved us 'in this way': by giving His Son. The focus is on the method of love, not the quantity. Quantity of love is shown elsewhere (nothing can separate us). Here the quality is shown — covenant love expressed through sacrifice.", color:"#1A2F4B" },
  { greek:"γάρ", transliteration:"gar", meaning:"For (because)", grammar:"Postpositive conjunction, the second most common conjunction in the NT (~1,041 occurrences). Always appears second in its clause. Introduces the reason or ground for what precedes it.", letters:[{l:"γ",name:"Gamma",lesson:3,note:"'g' — the opening sound of ground and reason"},{l:"α",name:"Alpha",lesson:1,note:"The fundamental vowel"},{l:"ρ",name:"Rho",lesson:17,note:"Rolling 'r' — carrying the weight of explanation"}], devotional:"γάρ is the hinge of John 3:16. Jesus has just told Nicodemus that the Son of Man must be lifted up (v.14). Why? γάρ — because God so loved the world. The cross is not an accident of history but the deliberate expression of divine love. Every 'for' in Scripture points to a reason, and here the reason is love.", color:"#1B7A6E" },
  { greek:"ἠγάπησεν", transliteration:"ēgapēsen", meaning:"Loved (completely)", grammar:"Aorist active indicative 3rd singular of ἀγαπάω (G25). The aorist views the action as a complete whole — God's act of love in giving His Son was a decisive, completed action. Not imperfect (ongoing) but aorist (done).", letters:[{l:"η",name:"Eta",lesson:7,note:"Long 'e' — the augment marking past tense"},{l:"γ",name:"Gamma",lesson:3,note:"'g' — the root of agape begins here"},{l:"α",name:"Alpha",lesson:1,note:"The 'a' of ἀγάπη"},{l:"π",name:"Pi",lesson:16,note:"'p' — like the pillars of love"},{l:"η",name:"Eta",lesson:7,note:"Long 'e' ending of the root"},{l:"σ",name:"Sigma",lesson:18,note:"Aorist sigma — marking the completed act"},{l:"ε",name:"Epsilon",lesson:5,note:"Short 'e' ending"},{l:"ν",name:"Nu",lesson:13,note:"Final 'n' — the third person ending"}], devotional:"ἠγάπησεν — God loved. The verb is aorist, completed. This is not a conditional or ongoing negotiation. God's love in the gift of Christ is a done deal — written in history, sealed in blood. You did not earn it. You cannot lose it. It happened.", color:"#2A5E58" },
  { greek:"ὁ θεός", transliteration:"ho theos", meaning:"God (the God)", grammar:"Nominative masculine singular with the definite article. θεός (G2316) appears 1,317 times in the NT. The article ὁ identifies the one true God — not 'a god' but 'the God', the God of Abraham, Isaac, and Jacob.", letters:[{l:"ο",name:"Omicron",lesson:15,note:"The article — pointing to the one God"},{l:"θ",name:"Theta",lesson:8,note:"'th' — the distinctive opening of theos"},{l:"ε",name:"Epsilon",lesson:5,note:"Short 'e'"},{l:"ο",name:"Omicron",lesson:15,note:"Short 'o'"},{l:"ς",name:"Sigma (final)",lesson:18,note:"Nominative ending — God as subject, God as actor"}], devotional:"ὁ θεός — the God. Not fate, not karma, not an impersonal force. The subject of John 3:16 is a Person. He is the one who loved, the one who gave. In Greek philosophy, the divine was distant and dispassionate. John's God is neither. He is close enough to love and generous enough to give His Son.", color:"#1B7A6E" },
  { greek:"τὸν κόσμον", transliteration:"ton kosmon", meaning:"The world", grammar:"Accusative masculine singular with article. κόσμος (G2889) appears 186 times in the NT. In John, 'the world' means the created order that has turned away from God — not the physical planet but rebellious humanity.", letters:[{l:"τ",name:"Tau",lesson:19,note:"Cross-shaped letter — fitting for the gift given to the world"},{l:"ο",name:"Omicron",lesson:15,note:"Accusative article"},{l:"ν",name:"Nu",lesson:13,note:"Article ending"},{l:"κ",name:"Kappa",lesson:10,note:"'k' — the hard opening of kosmos"},{l:"ο",name:"Omicron",lesson:15,note:"Short 'o'"},{l:"σ",name:"Sigma",lesson:18,note:"'s' — cosmos gives us 'cosmopolitan'"},{l:"μ",name:"Mu",lesson:12,note:"'m'"},{l:"ο",name:"Omicron",lesson:15,note:"Short 'o'"},{l:"ν",name:"Nu",lesson:13,note:"Accusative ending — the world as object of God's love"}], devotional:"τὸν κόσμον — the world. Not the righteous, not Israel, not the deserving. The world that rejected Him. The world that would crucify His Son. This is the scandal of grace: God loved the world that hated Him. The scope of divine love is not a select few but the entire rebellious cosmos.", color:"#1A2F4B" },
  { greek:"τὸν μονογενῆ", transliteration:"ton monogenē", meaning:"The only begotten / one and only", grammar:"Accusative masculine singular. μονογενής (G3439) from μόνος (only) + γένος (kind/type). Means 'one of a kind, unique' rather than 'only born'. Used of Isaac in Hebrews 11:17 — yet Abraham had other sons. The emphasis is on uniqueness.", letters:[{l:"μ",name:"Mu",lesson:12,note:"'m' — monos, the only one"},{l:"ο",name:"Omicron",lesson:15,note:"Short 'o'"},{l:"ν",name:"Nu",lesson:13,note:"'n'"},{l:"ο",name:"Omicron",lesson:15,note:"Short 'o'"},{l:"γ",name:"Gamma",lesson:3,note:"'g' — genos, of a unique kind"},{l:"ε",name:"Epsilon",lesson:5,note:"Short 'e'"},{l:"ν",name:"Nu",lesson:13,note:"'n'"},{l:"η",name:"Eta",lesson:7,note:"Long 'e' — accusative ending"}], devotional:"μονογενῆ — one of a kind. The Father did not give a copy, a substitute, or a representative. He gave His unique, irreplaceable Son. There is no spare. When God gave Christ, He gave everything He had. The gift was not surplus — it was treasure.", color:"#2A5E58" },
  { greek:"ἔδωκεν", transliteration:"edōken", meaning:"He gave", grammar:"Aorist active indicative 3rd singular of δίδωμι (G1325). Another aorist — a completed, decisive act. δίδωμι is a -μι verb (irregular class). The giving was not reluctant or partial; it was whole and finished.", letters:[{l:"ε",name:"Epsilon",lesson:5,note:"Augment — marking past tense"},{l:"δ",name:"Delta",lesson:4,note:"'d' — didomi begins with delta"},{l:"ω",name:"Omega",lesson:24,note:"Long 'o' — the great vowel of giving"},{l:"κ",name:"Kappa",lesson:10,note:"'k' — aorist stem change"},{l:"ε",name:"Epsilon",lesson:5,note:"Short 'e'"},{l:"ν",name:"Nu",lesson:13,note:"3rd person singular ending"}], devotional:"ἔδωκεν — He gave. Past tense, completed action. God did not lend His Son. He did not loan Him with conditions. He gave. The cross was not a transaction to be reversed but a gift to be received. And the nature of a gift is that the receiver need only open their hands.", color:"#1B7A6E" },
];

export const WORDS_ROM8V28 = [
  { greek:"τοῖς ἀγαπῶσιν", transliteration:"tois agapōsin", meaning:"To those who love", grammar:"Dative masculine plural present active participle of ἀγαπάω with article. Present tense: those who are continuously loving God — a present lifestyle, not a past event. The dative indicates the beneficiaries of God's working.", letters:[{l:"τ",name:"Tau",lesson:19,note:"Article — marking the specific group"},{l:"ο",name:"Omicron",lesson:15,note:"Short 'o'"},{l:"ι",name:"Iota",lesson:9,note:"Dative ending subscript"},{l:"ς",name:"Sigma (final)",lesson:18,note:"Article ending"},{l:"α",name:"Alpha",lesson:1,note:"Root of agape"},{l:"γ",name:"Gamma",lesson:3,note:"'g' — agapao"},{l:"α",name:"Alpha",lesson:1,note:"'a'"},{l:"π",name:"Pi",lesson:16,note:"'p'"},{l:"ω",name:"Omega",lesson:24,note:"Present tense stem vowel"},{l:"σ",name:"Sigma",lesson:18,note:"'s'"},{l:"ι",name:"Iota",lesson:9,note:"Participle ending"},{l:"ν",name:"Nu",lesson:13,note:"Masculine plural ending"}], devotional:"τοῖς ἀγαπῶσιν — to those who love. The promise of Romans 8:28 is not for everyone indiscriminately. It is for those whose lives are marked by love for God — present tense, ongoing, habitual. Not perfect love, but real love. Not love that never fails, but love that keeps returning.", color:"#1B7A6E" },
  { greek:"πάντα", transliteration:"panta", meaning:"All things", grammar:"Nominative or accusative neuter plural of πᾶς (G3956). 'All things' — not some things, not most things. The scope is total. πᾶς appears 1,244 times in the NT — the language of totality.", letters:[{l:"π",name:"Pi",lesson:16,note:"The gate — all things pass through here"},{l:"α",name:"Alpha",lesson:1,note:"'a' — beginning of 'all'"},{l:"ν",name:"Nu",lesson:13,note:"'n' sound"},{l:"τ",name:"Tau",lesson:19,note:"'t' — shaped like a cross"},{l:"α",name:"Alpha",lesson:1,note:"Plural neuter ending"}], devotional:"πάντα — all things. Not just the pleasant things, not just the suffering you understand. ALL things. The Greek is unambiguous. Paul includes his own shipwrecks, beatings, and imprisonment in this 'all'. When he wrote it, he wrote it from chains.", color:"#2A5E58" },
  { greek:"συνεργεῖ", transliteration:"synergei", meaning:"Works together", grammar:"Present active indicative 3rd singular of συνεργέω (G4903). Root of our word 'synergy'. The present tense indicates continuous, ongoing working-together — not a one-time intervention but a permanent divine activity.", letters:[{l:"σ",name:"Sigma",lesson:18,note:"'s' — together, united"},{l:"υ",name:"Upsilon",lesson:20,note:"'u' — the prefix σύν means 'with'"},{l:"ν",name:"Nu",lesson:13,note:"'n' completing 'syn'"},{l:"ε",name:"Epsilon",lesson:5,note:"Connecting vowel"},{l:"ρ",name:"Rho",lesson:17,note:"'r' of ergon — work"},{l:"γ",name:"Gamma",lesson:3,note:"'g' of 'ergon'"},{l:"ε",name:"Epsilon",lesson:5,note:"'e'"},{l:"ι",name:"Iota",lesson:9,note:"Present tense ending"}], devotional:"Συνεργεῖ — the God of the universe is in the business of making things work together. He is not passive. He is not watching. He is actively orchestrating. Your pain is not isolated, your joy is not random. Every thread is being woven.", color:"#1B7A6E" },
  { greek:"εἰς", transliteration:"eis", meaning:"Into / For / Toward", grammar:"Preposition governing the accusative case. εἰς (G1519) appears 1,768 times in the NT. Indicates direction, purpose, or result. Here it points to the goal: all things work together toward good.", letters:[{l:"ε",name:"Epsilon",lesson:5,note:"Short 'e' — the opening of direction"},{l:"ι",name:"Iota",lesson:9,note:"'i' — the smallest letter pointing the way"},{l:"ς",name:"Sigma (final)",lesson:18,note:"Final sigma — the destination is set"}], devotional:"εἰς — toward, into, for the purpose of. This tiny preposition carries the weight of divine intentionality. Things do not randomly end up good. They are being directed toward good. There is a destination, and God knows the way. Your chaos has a trajectory, and its name is ἀγαθόν.", color:"#2A5E58" },
  { greek:"ἀγαθόν", transliteration:"agathon", meaning:"Good", grammar:"Accusative neuter singular of ἀγαθός (G18). Not merely 'nice' or 'pleasant' but morally and ultimately good — good in God's estimation, not necessarily ours. The good here is conformity to the image of Christ (v.29).", letters:[{l:"α",name:"Alpha",lesson:1,note:"'a' — the first letter, the foundation of good"},{l:"γ",name:"Gamma",lesson:3,note:"'g' — the sound of grace"},{l:"α",name:"Alpha",lesson:1,note:"'a'"},{l:"θ",name:"Theta",lesson:8,note:"'th' — the breath of theos in the good"},{l:"ο",name:"Omicron",lesson:15,note:"Short 'o'"},{l:"ν",name:"Nu",lesson:13,note:"Accusative ending — good as the goal, the destination"}], devotional:"ἀγαθόν — good. Not your definition of good. God's. The next verse (v.29) defines it: 'to be conformed to the image of His Son.' The good God is working toward is not comfort, wealth, or ease. It is Christlikeness. And sometimes the road to Christlikeness runs through the valley of the shadow of death.", color:"#1A2F4B" },
];

export const WORDS_PHIL4V13 = [
  { greek:"πάντα", transliteration:"panta", meaning:"All things", grammar:"Accusative neuter plural of πᾶς (G3956). Same word as Romans 8:28 — total, comprehensive scope. In context, Paul refers to both abundance and need (v.12): he has learned the secret in every circumstance.", letters:[{l:"π",name:"Pi",lesson:16,note:"The gate of possibility"},{l:"α",name:"Alpha",lesson:1,note:"'a' — all-encompassing"},{l:"ν",name:"Nu",lesson:13,note:"'n'"},{l:"τ",name:"Tau",lesson:19,note:"Cross-shaped — all things under the cross"},{l:"α",name:"Alpha",lesson:1,note:"Neuter plural ending"}], devotional:"πάντα — all things. Paul does not say 'some things' or 'the easy things'. He says all things — hunger and plenty, prison and freedom, honor and shame. The secret is not circumstantial prosperity but transcendent sufficiency. All things, in Christ.", color:"#1B7A6E" },
  { greek:"ἰσχύω", transliteration:"ischuō", meaning:"I am strong / I can do", grammar:"Present active indicative 1st singular of ἰσχύω (G2480). Means 'to have strength, to be able, to prevail'. Present tense: continuous capability. Not 'I was strong once' but 'I am perpetually empowered'.", letters:[{l:"ι",name:"Iota",lesson:9,note:"'i' — the small letter of great strength"},{l:"σ",name:"Sigma",lesson:18,note:"'s'"},{l:"χ",name:"Chi",lesson:22,note:"'kh' — the Chi of Christos"},{l:"υ",name:"Upsilon",lesson:20,note:"'u'"},{l:"ω",name:"Omega",lesson:24,note:"Present tense ending — ongoing, never depleted"}], devotional:"ἰσχύω — I have strength. Not 'I grit my teeth harder' or 'I believe in myself'. Paul's strength is not self-generated. It is received. The man who wrote this was in a Roman prison, chained to a guard, facing possible execution. And he said: I am strong. Not because his circumstances changed, but because his source never runs dry.", color:"#1A2F4B" },
  { greek:"ἐν", transliteration:"en", meaning:"In", grammar:"Preposition governing the dative, indicating sphere or means. The same word that opens John 1:1. Here it indicates the sphere in which Paul's strength operates — 'in' the one empowering him. Location, not effort.", letters:[{l:"ε",name:"Epsilon",lesson:5,note:"Short 'e'"},{l:"ν",name:"Nu",lesson:13,note:"'n' — in, within, surrounded by"}], devotional:"ἐν — in. Two letters that change everything. Paul's strength is not 'from' Christ (as if he takes it and walks away) or 'because of' Christ (as if Christ merely inspires). It is 'in' Christ — Paul remains in Him, drawing strength as a branch draws life from the vine. Remove the vine, and the branch has nothing.", color:"#2A5E58" },
  { greek:"τῷ", transliteration:"tō", meaning:"The one (who)", grammar:"Dative masculine singular definite article, functioning as a substantive — 'the one'. Points to a specific person, not a concept. The article makes the empowerer personal and identifiable.", letters:[{l:"τ",name:"Tau",lesson:19,note:"Cross-shaped — the one who hung on Tau"},{l:"ω",name:"Omega",lesson:24,note:"Long 'o' — dative ending, pointing to the person"}], devotional:"τῷ — the one. Not 'a force', not 'positive energy', not 'the universe'. The one. A specific person with a name. Paul knows exactly who empowers him. It is not an abstraction but a relationship. The definite article insists: this is not generic spirituality. This is Christ.", color:"#1B7A6E" },
  { greek:"ἐνδυναμοῦντί", transliteration:"endynamounti", meaning:"Empowering / Strengthening", grammar:"Present active participle dative masculine singular of ἐνδυναμόω (G1743). From ἐν + δύναμις (dynamis = power). Root of 'dynamite' and 'dynamic'. Present participle: the one who is continuously, right now, in this moment, pouring strength into me.", letters:[{l:"ε",name:"Epsilon",lesson:5,note:"'e' — the prefix en-"},{l:"ν",name:"Nu",lesson:13,note:"'n' — completing 'en' (in)"},{l:"δ",name:"Delta",lesson:4,note:"'d' — dynamis begins here"},{l:"υ",name:"Upsilon",lesson:20,note:"'u'"},{l:"ν",name:"Nu",lesson:13,note:"'n'"},{l:"α",name:"Alpha",lesson:1,note:"'a'"},{l:"μ",name:"Mu",lesson:12,note:"'m'"},{l:"ο",name:"Omicron",lesson:15,note:"Short 'o'"},{l:"υ",name:"Upsilon",lesson:20,note:"'u'"},{l:"ν",name:"Nu",lesson:13,note:"'n'"},{l:"τ",name:"Tau",lesson:19,note:"'t' — participle marker"},{l:"ι",name:"Iota",lesson:9,note:"Dative ending — the one empowering me"}], devotional:"ἐνδυναμοῦντί — the one who is right now pouring dynamis into me. This is the heart of the verse. The present participle means the empowering never stops. Not 'the one who empowered me yesterday' or 'the one who will empower me someday'. Right now. In this prison cell. In this hunger. In this uncertainty. The dynamite of God is active.", color:"#2A5E58" },
  { greek:"με", transliteration:"me", meaning:"Me", grammar:"Accusative 1st person singular pronoun. The direct object of the empowering. Simple, personal, direct. Christ empowers me — not just humanity in general, but me specifically.", letters:[{l:"μ",name:"Mu",lesson:12,note:"'m' — me, myself"},{l:"ε",name:"Epsilon",lesson:5,note:"Short 'e' — the simplest pronoun, the most personal truth"}], devotional:"με — me. The most personal word in the verse. Not 'the church', not 'the apostles', not 'the worthy'. Me. Paul, the former persecutor. Paul, the prisoner. Paul, the one with a thorn in the flesh. If Christ empowers Paul, He empowers you. The promise is as personal as the pronoun.", color:"#1B7A6E" },
];

// ═══ READING REFLECTIONS (shown on completion) ═══

export const READING_REFLECTIONS = {
  john1v1: "John 1:1 contains three clauses, each with ἦν (was): the Word's eternal existence, the Word's relationship with God, and the Word's divine nature. Greek word order in the third clause — θεὸς ἦν ὁ λόγος — places 'God' first for emphasis, while the article on λόγος identifies the subject. The Logos bridges Greek philosophy (universal reason) and Hebrew theology (the creative Word of Genesis 1). In five words, John establishes the pre-existence, personality, and deity of Christ.",
  john3v16: "John 3:16 uses two aorist verbs — ἠγάπησεν (loved) and ἔδωκεν (gave) — both pointing to completed, decisive acts. God's love was not hesitant or conditional; it was done. The object is τὸν κόσμον (the world) — rebellious humanity, not a deserving audience. And the gift is τὸν μονογενῆ (the one-of-a-kind Son). Three theological earthquakes in one sentence: the lover, the loved, and the gift. Martin Luther called this verse 'the Gospel in miniature.'",
  rom8v28: "Romans 8:28 rests on συνεργεῖ — present tense, God is right now causing all things to cooperate toward good. The good (ἀγαθόν) is defined in the next verse: conformity to the image of Christ (v.29). Paul wrote this from experience — shipwrecked, beaten, imprisoned — yet he declares all things, not some, are being woven together. The promise is not that everything feels good, but that everything serves good in God's hands.",
  phil4v13: "Philippians 4:13 is perhaps the most misquoted verse in the Bible. Paul is not claiming unlimited personal ability. The context (v.11-12) is contentment in all circumstances — hunger and plenty, need and abundance. The key word is ἐνδυναμοῦντί — a present participle meaning 'the one who is right now empowering me'. The source of strength is external, continuous, and personal. It is not a motivational poster but a prison testimony.",
};

// ═══ DAILY CHALLENGE POOL (120 questions) ═══

const ALPHABET_CHALLENGES = [
  { q:"What is the name of this letter: Α α?", opts:["Alpha","Omega","Eta","Iota"], ans:0, explain:"Alpha (Α α) is the first letter of the Greek alphabet, from which we get the word 'alphabet' (alpha + beta)." },
  { q:"What is the name of this letter: Β β?", opts:["Delta","Beta","Theta","Pi"], ans:1, explain:"Beta (Β β) is the second letter, giving us words like 'Bible' (βιβλίον — little book)." },
  { q:"What is the name of this letter: Γ γ?", opts:["Gamma","Sigma","Kappa","Zeta"], ans:0, explain:"Gamma (Γ γ) makes the 'g' sound and appears in words like εὐαγγέλιον (gospel)." },
  { q:"What is the name of this letter: Δ δ?", opts:["Theta","Beta","Delta","Phi"], ans:2, explain:"Delta (Δ δ) gives us the triangle-shaped river 'delta' — from its uppercase shape Δ." },
  { q:"What is the name of this letter: Ε ε?", opts:["Eta","Epsilon","Upsilon","Iota"], ans:1, explain:"Epsilon (Ε ε) is the short 'e' vowel, distinct from Eta (η) which is the long 'e'." },
  { q:"What is the name of this letter: Ζ ζ?", opts:["Xi","Zeta","Sigma","Chi"], ans:1, explain:"Zeta (Ζ ζ) makes the 'z' or 'dz' sound. It appears in words like ζωή (life)." },
  { q:"What is the name of this letter: Η η?", opts:["Epsilon","Iota","Eta","Omega"], ans:2, explain:"Eta (Η η) is the long 'e' vowel. It appears in words like εἰρήνη (peace)." },
  { q:"What is the name of this letter: Θ θ?", opts:["Phi","Theta","Rho","Tau"], ans:1, explain:"Theta (Θ θ) makes the 'th' sound, as in θεός (God) and θάνατος (death)." },
  { q:"What is the name of this letter: Ι ι?", opts:["Iota","Upsilon","Eta","Alpha"], ans:0, explain:"Iota (Ι ι) is the smallest letter — Jesus said 'not one iota' shall pass from the law (Matt 5:18)." },
  { q:"What is the name of this letter: Κ κ?", opts:["Chi","Kappa","Gamma","Xi"], ans:1, explain:"Kappa (Κ κ) makes the 'k' sound. It appears in κόσμος (world) and καρδία (heart)." },
  { q:"What is the name of this letter: Λ λ?", opts:["Mu","Lambda","Nu","Pi"], ans:1, explain:"Lambda (Λ λ) makes the 'l' sound. It appears in λόγος (word) and λαός (people)." },
  { q:"What is the name of this letter: Μ μ?", opts:["Nu","Mu","Omicron","Sigma"], ans:1, explain:"Mu (Μ μ) makes the 'm' sound. It appears in μαθητής (disciple) and μαρτυρία (witness)." },
  { q:"What is the name of this letter: Ν ν?", opts:["Mu","Eta","Nu","Upsilon"], ans:2, explain:"Nu (Ν ν) makes the 'n' sound. Be careful not to confuse lowercase ν with uppercase Υ!" },
  { q:"What is the name of this letter: Ξ ξ?", opts:["Chi","Psi","Xi","Zeta"], ans:2, explain:"Xi (Ξ ξ) makes the 'x' or 'ks' sound. It's one of the trickier letters to write." },
  { q:"What is the name of this letter: Ο ο?", opts:["Omega","Omicron","Upsilon","Eta"], ans:1, explain:"Omicron (Ο ο) is the short 'o'. Its name literally means 'little o' (ὀ μικρόν)." },
  { q:"What is the name of this letter: Π π?", opts:["Rho","Phi","Pi","Psi"], ans:2, explain:"Pi (Π π) makes the 'p' sound. It appears in πίστις (faith) and πνεῦμα (spirit)." },
  { q:"What is the name of this letter: Ρ ρ?", opts:["Rho","Pi","Sigma","Beta"], ans:0, explain:"Rho (Ρ ρ) makes the 'r' sound. Looks like English 'P' but sounds like 'R'!" },
  { q:"What is the name of this letter: Σ σ/ς?", opts:["Zeta","Xi","Chi","Sigma"], ans:3, explain:"Sigma (Σ σ/ς) has two lowercase forms: σ in the middle of words and ς at the end." },
  { q:"What is the name of this letter: Τ τ?", opts:["Theta","Tau","Upsilon","Pi"], ans:1, explain:"Tau (Τ τ) makes the 't' sound. Its shape resembles a cross — σταυρός (cross) begins with sigma-tau." },
  { q:"What is the name of this letter: Υ υ?", opts:["Upsilon","Omicron","Iota","Eta"], ans:0, explain:"Upsilon (Υ υ) makes the 'u' or 'ü' sound. It appears in υἱός (son) and ὕδωρ (water)." },
  { q:"What is the name of this letter: Φ φ?", opts:["Chi","Psi","Pi","Phi"], ans:3, explain:"Phi (Φ φ) makes the 'f' or 'ph' sound. It appears in φῶς (light) and φιλέω (to love)." },
  { q:"What is the name of this letter: Χ χ?", opts:["Chi","Xi","Psi","Kappa"], ans:0, explain:"Chi (Χ χ) makes the 'kh' sound. Χριστός (Christ) begins with Chi — hence 'Xmas'." },
  { q:"What is the name of this letter: Ψ ψ?", opts:["Phi","Xi","Psi","Omega"], ans:2, explain:"Psi (Ψ ψ) makes the 'ps' sound. It appears in ψυχή (soul/psyche)." },
  { q:"What is the name of this letter: Ω ω?", opts:["Omicron","Alpha","Upsilon","Omega"], ans:3, explain:"Omega (Ω ω) is the long 'o' and last letter. Jesus said 'I am the Alpha and the Omega' (Rev 1:8)." },
  { q:"Which letter looks like an English 'P' but sounds like 'R'?", opts:["Pi","Phi","Rho","Beta"], ans:2, explain:"Rho (Ρ ρ) looks like English 'P' but makes the 'r' sound — a classic trap for beginners!" },
  { q:"Which two Greek letters make up the word 'alphabet'?", opts:["Alpha + Beta","Alpha + Omega","Gamma + Delta","Epsilon + Zeta"], ans:0, explain:"The word 'alphabet' comes from the first two Greek letters: Alpha (Α) + Beta (Β)." },
  { q:"Which letter has two lowercase forms (medial and final)?", opts:["Nu","Sigma","Gamma","Rho"], ans:1, explain:"Sigma uses σ in the middle of words and ς at the end. E.g., σοφός (wise)." },
  { q:"What is the numeric value of Alpha (Α)?", opts:["0","1","10","100"], ans:1, explain:"In Greek numerals (isopsephy), Alpha = 1, Beta = 2, Gamma = 3, and so on." },
  { q:"Jesus said 'I am the ___ and the ___' (Rev 1:8)", opts:["Alpha and Omega","Gamma and Delta","Epsilon and Eta","Iota and Kappa"], ans:0, explain:"'I am the Alpha and the Omega' — the first and last letters, meaning the beginning and the end of all things." },
  { q:"Which letter is shaped like a cross?", opts:["Chi","Tau","Sigma","Theta"], ans:1, explain:"Tau (Τ) is shaped like a cross. Early Christians used it as a symbol. σταυρός (cross) contains a tau." },
  { q:"What sound does Theta (Θ) make?", opts:["'t' as in top","'th' as in think","'f' as in phone","'k' as in king"], ans:1, explain:"Theta (Θ θ) makes the 'th' sound. θεός (God), θάνατος (death), θρόνος (throne)." },
  { q:"Which is the smallest Greek letter?", opts:["Omicron","Epsilon","Iota","Nu"], ans:2, explain:"Iota (Ι ι) is the smallest. Jesus references it in Matthew 5:18: 'not one iota shall pass from the law.'" },
  { q:"Omicron literally means:", opts:["Big O","Little O","First O","Last O"], ans:1, explain:"Ὀ μικρόν = 'little o'. Omega (Ὦ μέγα) = 'big O'. They distinguish the short and long 'o' sounds." },
  { q:"What letter begins Χριστός (Christ)?", opts:["Kappa","Chi","Psi","Theta"], ans:1, explain:"Chi (Χ) begins Χριστός. This is why 'Xmas' is a valid abbreviation — X = Chi = Christ." },
  { q:"How many letters are in the Greek alphabet?", opts:["22","24","26","28"], ans:1, explain:"Greek has 24 letters (Alpha through Omega), compared to Hebrew's 22 and English's 26." },
  { q:"Which letter sounds like 'ps' as in 'psychology'?", opts:["Phi","Xi","Psi","Sigma"], ans:2, explain:"Psi (Ψ ψ) makes the 'ps' sound. ψυχή (soul) gives us 'psychology' and 'psyche'." },
  { q:"Which is the long 'e' vowel?", opts:["Epsilon","Eta","Iota","Upsilon"], ans:1, explain:"Eta (Η η) is the long 'e'. Epsilon (Ε ε) is the short 'e'. This distinction matters for grammar." },
  { q:"What does the letter name 'Delta' give us in geography?", opts:["Desert","Mountain","River delta","Valley"], ans:2, explain:"A river delta is named after the triangular shape of uppercase Delta (Δ) — the silt deposit at a river mouth." },
  { q:"Which letter makes the 'ks' sound?", opts:["Chi","Xi","Psi","Sigma"], ans:1, explain:"Xi (Ξ ξ) makes the 'ks' (or 'x') sound. It's a double consonant, like Psi (ps)." },
  { q:"What's special about Nu (ν) and Upsilon (υ) for beginners?", opts:["They sound alike","They look alike","They're vowels","They're silent"], ans:1, explain:"Lowercase ν (nu) and υ (upsilon) can look similar in handwriting — a common source of confusion for students." },
];

const VOCAB_CHALLENGES = [
  { q:"What does θεός (theos) mean?", opts:["Lord","God","Spirit","King"], ans:1, explain:"θεός (G2316) = God. Appears 1,317 times in the NT. Root of 'theology' and 'theocracy'." },
  { q:"What does ἀγάπη (agapē) mean?", opts:["Faith","Hope","Love","Grace"], ans:2, explain:"ἀγάπη (G26) = unconditional love. The highest Greek word for love. Root of 'agape feast'." },
  { q:"What does λόγος (logos) mean?", opts:["Law","Light","Word/Reason","Life"], ans:2, explain:"λόγος (G3056) = word, reason, logic. John 1:1 identifies the Logos as Christ. Root of '-ology' words." },
  { q:"What does πίστις (pistis) mean?", opts:["Peace","Faith/Trust","Prayer","Power"], ans:1, explain:"πίστις (G4102) = faith, trust, belief. Appears 243 times in the NT. Key term in Paul's theology." },
  { q:"What does χάρις (charis) mean?", opts:["Charity","Character","Grace","Church"], ans:2, explain:"χάρις (G5485) = grace, unmerited favor. Root of 'charisma' and 'eucharist' (thanksgiving)." },
  { q:"What does κύριος (kyrios) mean?", opts:["Christ","King","Lord","God"], ans:2, explain:"κύριος (G2962) = Lord, master. Appears 717 times in the NT. The confession 'Jesus is Lord' = Ἰησοῦς κύριος." },
  { q:"What does ἐκκλησία (ekklēsia) mean?", opts:["Ecclesiastic","Church/Assembly","Cathedral","Temple"], ans:1, explain:"ἐκκλησία (G1577) = the called-out assembly, church. From ἐκ (out) + καλέω (to call). Not a building but a people." },
  { q:"What does εὐαγγέλιον (euangelion) mean?", opts:["Angel","Evangelism","Gospel/Good News","Epistle"], ans:2, explain:"εὐαγγέλιον (G2098) = good news, gospel. From εὖ (good) + ἄγγελος (messenger). Root of 'evangelist'." },
  { q:"What does πνεῦμα (pneuma) mean?", opts:["Pneumonia","Power","Prayer","Spirit/Breath"], ans:3, explain:"πνεῦμα (G4151) = spirit, breath, wind. Used for the Holy Spirit (τὸ Πνεῦμα τὸ Ἅγιον). Root of 'pneumatic'." },
  { q:"What does ἁμαρτία (hamartia) mean?", opts:["Harmony","Sin/Missing the mark","Hammer","Heresy"], ans:1, explain:"ἁμαρτία (G266) = sin. Literally 'missing the mark' — an archery term. The universal human condition (Rom 3:23)." },
  { q:"What does σωτηρία (sōtēria) mean?", opts:["Sorrow","Suffering","Salvation","Sovereignty"], ans:2, explain:"σωτηρία (G4991) = salvation, deliverance. From σώζω (to save). Jesus' name (Ἰησοῦς) means 'Yahweh saves'." },
  { q:"What does δικαιοσύνη (dikaiosunē) mean?", opts:["Discipline","Righteousness","Dignity","Decision"], ans:1, explain:"δικαιοσύνη (G1343) = righteousness, justice. A central term in Romans. God's righteousness is both His character and His gift." },
  { q:"What does βασιλεία (basileia) mean?", opts:["Basilica","Battle","Kingdom/Reign","Bishop"], ans:2, explain:"βασιλεία (G932) = kingdom, reign, royal rule. 'The kingdom of God/heaven' appears 100+ times in the Gospels." },
  { q:"What does ζωή (zōē) mean?", opts:["Zoo","Zone","Zeal","Life"], ans:3, explain:"ζωή (G2222) = life (especially eternal, spiritual life). 'I am the way, the truth, and the ζωή' (John 14:6). Root of 'zoology'." },
  { q:"What does ἀλήθεια (alētheia) mean?", opts:["Allegory","Truth","Altar","Authority"], ans:1, explain:"ἀλήθεια (G225) = truth. Literally 'un-hidden' (α-privative + λήθη = forgetfulness). Truth is what is uncovered." },
  { q:"What does εἰρήνη (eirēnē) mean?", opts:["Eternity","Energy","Peace","Earth"], ans:2, explain:"εἰρήνη (G1515) = peace. The Greek equivalent of Hebrew שָׁלוֹם (shalom). Name 'Irene' derives from it." },
  { q:"What does μετάνοια (metanoia) mean?", opts:["Metaphor","Memory","Repentance","Miracle"], ans:2, explain:"μετάνοια (G3341) = repentance, change of mind. From μετά (after/change) + νοῦς (mind). A complete mental transformation." },
  { q:"What does δόξα (doxa) mean?", opts:["Doctrine","Glory/Honor","Dogma","Doubt"], ans:1, explain:"δόξα (G1391) = glory, honor, splendor. Root of 'doxology' (a hymn of praise). God's visible radiance and worth." },
  { q:"What does σταυρός (stauros) mean?", opts:["Star","Stone","Staff","Cross"], ans:3, explain:"σταυρός (G4716) = cross, stake. The instrument of Jesus' execution, transformed into the supreme symbol of redemption." },
  { q:"What does ἀνάστασις (anastasis) mean?", opts:["Analysis","Ancestry","Resurrection","Anesthesia"], ans:2, explain:"ἀνάστασις (G386) = resurrection, rising up. From ἀνά (up) + ἵστημι (to stand). Name 'Anastasia' means 'resurrection'." },
  { q:"What does παρουσία (parousia) mean?", opts:["Paradise","Parable","Presence/Coming","Parish"], ans:2, explain:"παρουσία (G3952) = coming, arrival, presence. The technical term for Christ's Second Coming. Literally 'being alongside'." },
  { q:"What does μαθητής (mathētēs) mean?", opts:["Mathematician","Disciple/Learner","Master","Martyr"], ans:1, explain:"μαθητής (G3101) = disciple, learner. From μανθάνω (to learn). Root of 'mathematics'. Jesus had μαθηταί — learners." },
  { q:"What does ἀπόστολος (apostolos) mean?", opts:["Apostle/Sent one","Apology","Apostrophe","Apothecary"], ans:0, explain:"ἀπόστολος (G652) = one sent with authority. From ἀπό (from) + στέλλω (to send). More than a messenger — a commissioned representative." },
  { q:"What does δύναμις (dynamis) mean?", opts:["Dynasty","Dynamite","Power/Miracle","Danger"], ans:2, explain:"δύναμις (G1411) = power, might, miracle. Root of 'dynamite' and 'dynamic'. Acts 1:8: 'You shall receive δύναμις.'" },
  { q:"What does κόσμος (kosmos) mean?", opts:["Cosmos/World","Chaos","Kingdom","Church"], ans:0, explain:"κόσμος (G2889) = world, ordered universe. In John's writings, often means 'the fallen world system'. Root of 'cosmopolitan'." },
  { q:"What does ψυχή (psychē) mean?", opts:["Psychic","Psychology","Soul/Life","Spirit"], ans:2, explain:"ψυχή (G5590) = soul, life, self. Distinct from πνεῦμα (spirit). Root of 'psychology'. Mark 8:36: 'What profits a man to gain the world and lose his ψυχή?'" },
  { q:"What does ἄγγελος (angelos) mean?", opts:["Anger","Angel/Messenger","Angle","Anchor"], ans:1, explain:"ἄγγελος (G32) = messenger, angel. Used for both human messengers and divine beings. Root of 'angel' and 'evangel'." },
  { q:"What does κηρύσσω (kēryssō) mean?", opts:["To curse","To preach/proclaim","To keep","To know"], ans:1, explain:"κηρύσσω (G2784) = to herald, preach, proclaim. A κῆρυξ (herald) delivered the king's official announcements. Preaching is heralding God's decree." },
  { q:"What does πιστεύω (pisteuō) mean?", opts:["To pity","To believe/trust","To pray","To praise"], ans:1, explain:"πιστεύω (G4100) = to believe, trust, have faith. From πίστις (faith). John 3:16: 'whoever πιστεύων (believing) in Him'." },
  { q:"What does ἐλπίς (elpis) mean?", opts:["Help","Hope","Elixir","Eclipse"], ans:1, explain:"ἐλπίς (G1680) = hope. Not wishful thinking but confident expectation. Romans 5:5: 'Hope does not disappoint.'" },
  { q:"What does σάρξ (sarx) mean?", opts:["Search","Sarcasm","Flesh/Body","Soul"], ans:2, explain:"σάρξ (G4561) = flesh, human nature. John 1:14: 'The Word became σάρξ.' Paul contrasts flesh (σάρξ) and Spirit (πνεῦμα)." },
  { q:"What does οὐρανός (ouranos) mean?", opts:["Uranus","Ocean","Universe","Heaven/Sky"], ans:3, explain:"οὐρανός (G3772) = heaven, sky. 'Our Father in the οὐρανοῖς (heavens).' The planet Uranus takes its name from this word." },
  { q:"What does αἷμα (haima) mean?", opts:["Home","Blood","Harmony","Aim"], ans:1, explain:"αἷμα (G129) = blood. 'The blood of Jesus Christ His Son cleanses us from all sin' (1 John 1:7). Root of 'hematology'." },
  { q:"What does προσευχή (proseuchē) mean?", opts:["Prophecy","Procession","Prayer","Proverb"], ans:2, explain:"προσευχή (G4335) = prayer. From πρός (toward) + εὔχομαι (to wish/pray). Prayer is directing our heart toward God." },
  { q:"What does ἔργον (ergon) mean?", opts:["Error","Energy","Ego","Work/Deed"], ans:3, explain:"ἔργον (G2041) = work, deed, action. Root of 'ergonomic' and 'synergy'. James 2:26: 'Faith without ἔργα (works) is dead.'" },
  { q:"What does νόμος (nomos) mean?", opts:["Name","Number","Law","Norm"], ans:2, explain:"νόμος (G3551) = law, principle. Usually refers to the Torah (Mosaic Law). Root of '-nomy' as in 'astronomy' (star-law)." },
  { q:"What does ἱερόν (hieron) mean?", opts:["Hero","Hieroglyphic","Temple","Heaven"], ans:2, explain:"ἱερόν (G2411) = temple (the entire complex). Distinct from ναός (the inner sanctuary). Root of 'hierarchy'." },
  { q:"What does φῶς (phōs) mean?", opts:["Phone","Photo","Light","Fire"], ans:2, explain:"φῶς (G5457) = light. John 1:5: 'The light shines in the darkness.' Root of 'photograph' (light-writing) and 'phosphorus'." },
  { q:"What does θάνατος (thanatos) mean?", opts:["Thanks","Throne","Thought","Death"], ans:3, explain:"θάνατος (G2288) = death. 1 Cor 15:55: 'O death (θάνατε), where is thy sting?' 'Euthanasia' = εὖ (good) + θάνατος." },
  { q:"What does βαπτίζω (baptizō) mean?", opts:["To baptize/immerse","To bless","To bind","To believe"], ans:0, explain:"βαπτίζω (G907) = to dip, immerse, baptize. Originally used for dyeing cloth by immersion. John the βαπτιστής (Baptist) = the Immerser." },
];

const GRAMMAR_CHALLENGES = [
  { q:"What tense is ἠγάπησεν (ēgapēsen)?", opts:["Present","Aorist","Imperfect","Perfect"], ans:1, explain:"The η- augment and -σ- marker signal the aorist tense — a completed past action. God loved: done deal." },
  { q:"What case indicates the subject of a Greek verb?", opts:["Genitive","Dative","Nominative","Accusative"], ans:2, explain:"The nominative case marks the subject. In ὁ θεός ἠγάπησεν, θεός is nominative — God is the one who loved." },
  { q:"What does the definite article ὁ (ho) indicate?", opts:["Indefinite","Definite","Possessive","Reflexive"], ans:1, explain:"ὁ is the masculine nominative singular definite article = 'the'. Greek has no indefinite article ('a/an')." },
  { q:"The imperfect tense ἦν (ēn) indicates:", opts:["Future action","Completed action","Continuous past action","Command"], ans:2, explain:"Imperfect = continuous past. ἦν = 'was (continuously)'. John 1:1: The Word was (always already existing)." },
  { q:"What is the dative case typically used for?", opts:["Subject","Direct object","Indirect object/Means","Possession"], ans:2, explain:"Dative = to/for/with/by. 'Ἐν ἀρχῇ' — ἀρχῇ is dative: 'in the beginning'. It marks the indirect object or instrument." },
  { q:"How many cases does Classical/Biblical Greek have?", opts:["3","4","5","6"], ans:2, explain:"Five cases: Nominative (subject), Genitive (possession), Dative (indirect object), Accusative (direct object), Vocative (address)." },
  { q:"What voice is ἠγάπησεν in?", opts:["Active","Middle","Passive","Deponent"], ans:0, explain:"Active voice — the subject (God) performs the action (loved). Middle = subject acts on itself. Passive = receives the action." },
  { q:"A present participle like ἀγαπῶσιν indicates:", opts:["Completed action","Ongoing action","Future action","One-time action"], ans:1, explain:"Present participle = ongoing, continuous action. 'Those who are (continuously) loving God' — a lifestyle, not a moment." },
  { q:"What gender is ἐκκλησία (church)?", opts:["Masculine","Feminine","Neuter","Common"], ans:1, explain:"ἐκκλησία is feminine (1st declension, -α ending). In Greek, grammatical gender ≠ natural gender for most nouns." },
  { q:"The genitive case is primarily used for:", opts:["Subject","Possession/Source","Direct object","Location"], ans:1, explain:"Genitive = of/from. 'υἱὸς τοῦ θεοῦ' = Son of God. τοῦ θεοῦ is genitive — showing relationship and source." },
  { q:"What does the augment ἠ- (before γάπησεν) signal?", opts:["Future","Past tense","Subjunctive","Imperative"], ans:1, explain:"The augment (ε- or η-) on a verb signals past tense in the indicative mood. It's the 'time stamp' of Greek verbs." },
  { q:"What mood expresses commands in Greek?", opts:["Indicative","Subjunctive","Imperative","Optative"], ans:2, explain:"Imperative mood = commands. 'πιστεύετε!' (Believe!) is imperative. Present imperative = keep on doing; Aorist = just do it." },
  { q:"In θεὸς ἦν ὁ λόγος, the subject is:", opts:["θεός","ὁ λόγος","ἦν","None"], ans:1, explain:"The article (ὁ) marks the subject. ὁ λόγος = the Word (subject). θεός without the article = the predicate: 'God was the Word.'" },
  { q:"What does the aorist tense emphasize?", opts:["Duration of action","Completed/Whole action","Repeated action","Future action"], ans:1, explain:"Aorist views the action as a complete whole, a snapshot. Imperfect = ongoing movie. Aorist = single photograph." },
  { q:"What declension are most feminine nouns in -η/-α?", opts:["1st Declension","2nd Declension","3rd Declension","4th Declension"], ans:0, explain:"1st declension = mostly feminine nouns ending in -η or -α. E.g., ἀρχή, ἀγάπη, ψυχή, ἐκκλησία." },
  { q:"What word class is ἐν (en)?", opts:["Conjunction","Preposition","Adverb","Pronoun"], ans:1, explain:"ἐν = preposition governing the dative case. Means 'in, within, among'. One of the most common NT words (~2,752x)." },
  { q:"The accusative case is primarily used for:", opts:["Subject","Possession","Direct object","Address"], ans:2, explain:"Accusative = direct object. 'ἠγάπησεν τὸν κόσμον' — τὸν κόσμον is accusative: 'loved the world'." },
  { q:"What is a postpositive word?", opts:["Never first in clause","Always last","Can be anywhere","Always first"], ans:0, explain:"Postpositive words (γάρ, δέ, οὖν) never stand first in their clause. γάρ = 'for' but always in position 2+." },
  { q:"What does σύν- prefix mean in συνεργέω?", opts:["Against","Before","With/Together","After"], ans:2, explain:"σύν = with, together. Synergy (συνεργέω) = working together. Synagogue (συναγωγή) = gathering together." },
  { q:"The vocative case is used for:", opts:["Possession","Direct address","Indirect object","Subject"], ans:1, explain:"Vocative = direct address. 'Κύριε!' (Lord!), 'Πάτερ!' (Father!). Often identical to nominative forms." },
  { q:"What is a deponent verb?", opts:["Has no meaning","Middle/Passive form, active meaning","Only in past","Always imperative"], ans:1, explain:"Deponent verbs look middle or passive but have active meaning. E.g., ἔρχομαι = 'I come' (middle form, active sense)." },
  { q:"Perfect tense in Greek indicates:", opts:["Simple past","Past with present result","Future","Ongoing past"], ans:1, explain:"Perfect = completed action with ongoing results. γέγραπται = 'it stands written' (written in the past, still in effect now)." },
  { q:"What conjunction means 'and' and appears 9,000+ times?", opts:["δέ","ἀλλά","γάρ","καί"], ans:3, explain:"καί (G2532) = and, also, even. The most frequent conjunction in the NT. Simple but foundational to Greek sentence structure." },
  { q:"What type of pronoun is αὐτός?", opts:["Relative","Demonstrative","Personal (3rd person)","Reflexive"], ans:2, explain:"αὐτός = he/she/it (3rd person pronoun). Also means 'self' or 'same' depending on position. αὐτός ὁ θεός = God Himself." },
  { q:"In Greek, the subjunctive mood is used for:", opts:["Facts","Commands","Possibility/Purpose","Past events"], ans:2, explain:"Subjunctive = possibility, purpose, exhortation. ἵνα + subjunctive = 'in order that'. Not certainty but intention." },
  { q:"What is the middle voice?", opts:["Subject acts","Subject receives","Subject acts on itself or for itself","No subject"], ans:2, explain:"Middle voice = the subject acts on/for itself or with personal interest. λούομαι = 'I wash myself'. Between active and passive." },
  { q:"What does the prefix ἀ- (alpha privative) do?", opts:["Intensifies","Negates","Locates","Compares"], ans:1, explain:"Alpha privative = 'not, un-, without'. ἀ-θάνατος = immortal (un-death). ἀ-λήθεια = truth (un-forgetfulness)." },
  { q:"The future tense marker in Greek is:", opts:["-σ-","-κ-","-θ-","-μ-"], ans:0, explain:"Future tense adds -σ- to the verb stem. λύω → λύσω (I will loose). The sigma is the 'future stamp'." },
  { q:"What type of verb is εἰμί (to be)?", opts:["Regular -ω verb","Contract verb","Irregular/-μι verb","Deponent"], ans:2, explain:"εἰμί is highly irregular — a -μι verb with no predictable pattern. Forms: εἰμί, εἶ, ἐστίν, ἐσμέν, ἐστέ, εἰσίν. Must be memorized." },
  { q:"What does ὅτι introduce?", opts:["Purpose clause","Result clause","Content clause ('that')","Conditional"], ans:2, explain:"ὅτι = 'that' or 'because'. Introduces indirect speech: λέγω ὅτι = 'I say that...' Context determines 'that' vs 'because'." },
  { q:"What tense is γέγραπται (gegraptai)?", opts:["Aorist","Present","Imperfect","Perfect"], ans:3, explain:"γέγραπται = perfect passive: 'it has been written (and remains so)'. The reduplication (γε-) and -ται ending signal perfect passive." },
  { q:"What role does a participle play?", opts:["Only a verb","Only a noun","Verbal adjective","Preposition"], ans:2, explain:"Participles are verbal adjectives — they have verb tense/voice AND can modify nouns. 'The believing one' (ὁ πιστεύων) = substantive participle." },
  { q:"What is a Koine Greek distinctive vs Classical?", opts:["More cases","Simpler grammar","No articles","No participles"], ans:1, explain:"Koine ('common') Greek simplified Classical forms: less optative, simpler syntax, broader vocabulary. It was the lingua franca of the Roman Empire." },
  { q:"The infinitive in Greek can function as:", opts:["Only a verb","A verbal noun","Only an adjective","A preposition"], ans:1, explain:"The infinitive is a verbal noun. πιστεύειν = 'to believe' or 'believing'. Can be subject: τὸ πιστεύειν = 'the act of believing'." },
  { q:"What does Granville Sharp's Rule address?", opts:["Verb tenses","Article + noun + καί + noun","Prepositions","Word order"], ans:1, explain:"When two singular nouns share one article (ὁ A καὶ B), they refer to the same person. Titus 2:13: 'our God and Savior Jesus Christ'." },
  { q:"What is a genitive absolute?", opts:["A proper noun","An independent participial phrase","A superlative","A type of verb"], ans:1, explain:"Genitive absolute = participle + noun in genitive, grammatically independent from the main clause. Common in narrative: 'While X was happening, Y occurred.'" },
  { q:"How does Greek indicate emphasis?", opts:["Capitalization","Italics","Word order changes","Punctuation"], ans:2, explain:"Greek uses word order for emphasis. Moving a word to the front of a clause = emphasis. θεὸς ἦν ὁ λόγος — 'God was the Word' (deity emphasized)." },
  { q:"The pluperfect tense indicates:", opts:["Future perfect","Past perfect (had done)","Present result","Habitual past"], ans:1, explain:"Pluperfect = past completed action with results before another past event. ἐγεγράφειν = 'I had written'. Relatively rare in the NT." },
  { q:"What preposition means 'out of/from'?", opts:["εἰς","ἐν","ἐκ/ἐξ","ἐπί"], ans:2, explain:"ἐκ (before consonants) / ἐξ (before vowels) = out of, from. Governs the genitive. ἐξ ὕδατος = 'out of water' (John 3:5)." },
  { q:"What is the optative mood?", opts:["Wish/Possibility (rare in NT)","Command","Factual statement","Question"], ans:0, explain:"The optative expresses wishes and remote possibilities. μὴ γένοιτο = 'May it never be!' (Paul's favorite emphatic denial). Rare in Koine." },
];

export const DAILY_CHALLENGES = { alphabet: ALPHABET_CHALLENGES, vocab: VOCAB_CHALLENGES, grammar: GRAMMAR_CHALLENGES };

